-- Migration 011: Tabelas de índices monetários (IPCA-E e IPCA) para cálculo ADC 58/59 STF
-- IPCA-E = série BACEN 10764, IPCA = série BACEN 433
-- mes_ano = primeiro dia do mês (ex: '2024-01-01' = janeiro/2024)
-- valor = percentual mensal (ex: 0.42 = 0,42% ao mês)

CREATE TABLE IF NOT EXISTS ipca_e_historico (
  mes_ano DATE PRIMARY KEY,
  valor NUMERIC(10,4) NOT NULL
);

CREATE TABLE IF NOT EXISTS ipca_historico (
  mes_ano DATE PRIMARY KEY,
  valor NUMERIC(10,4) NOT NULL
);

